import{_ as t,o as a,c as s,ag as l}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"Core Guides","description":"","frontmatter":{},"headers":[],"relativePath":"guides.md","filePath":"guides.md"}'),n={name:"guides.md"};function o(i,e,r,p,d,c){return a(),s("div",null,[...e[0]||(e[0]=[l(`<h1 id="core-guides" tabindex="-1">Core Guides <a class="header-anchor" href="#core-guides" aria-label="Permalink to &quot;Core Guides&quot;">​</a></h1><p>This section helps you plug LinkedQL into a real application — whether your database lives locally, on a server, or across a runtime boundary.</p><p>Your final setup remains: one query interface, regardless of where your data lives.</p><hr><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>Install the package from npm:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">npm</span><span style="color:#C3E88D;"> install</span><span style="color:#C3E88D;"> @linked-db/linked-ql</span></span></code></pre></div><p>Each entry point corresponds to a deployment shape — you only import what your app needs.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Client</th><th style="text-align:left;">Import Path</th><th style="text-align:left;">Guide</th></tr></thead><tbody><tr><td style="text-align:left;"><code>PGClient</code></td><td style="text-align:left;"><code>@linked-db/linked-ql/postgres</code></td><td style="text-align:left;"><a href="/guides/postgresql">PostgreSQL</a></td></tr><tr><td style="text-align:left;"><code>MySQLClient</code></td><td style="text-align:left;"><code>@linked-db/linked-ql/mysql</code></td><td style="text-align:left;"><a href="/guides/mysql">MySQL</a></td></tr><tr><td style="text-align:left;"><code>MariaDBClient</code></td><td style="text-align:left;"><code>@linked-db/linked-ql/mariadb</code></td><td style="text-align:left;"><a href="/guides/mariadb">MariaDB</a></td></tr><tr><td style="text-align:left;"><code>FlashQL</code></td><td style="text-align:left;"><code>@linked-db/linked-ql/flashql</code></td><td style="text-align:left;"><a href="/guides/flashql">FlashQL</a></td></tr><tr><td style="text-align:left;"><code>EdgeClient</code></td><td style="text-align:left;"><code>@linked-db/linked-ql/edge</code></td><td style="text-align:left;"><a href="/guides/edge">Edge</a></td></tr><tr><td style="text-align:left;"><code>EdgeWorker</code></td><td style="text-align:left;"><code>@linked-db/linked-ql/edge-worker</code></td><td style="text-align:left;"><a href="/guides/edge">Edge</a></td></tr></tbody></table><hr><h2 id="core-interface" tabindex="-1">Core Interface <a class="header-anchor" href="#core-interface" aria-label="Permalink to &quot;Core Interface&quot;">​</a></h2><p>Every LinkedQL client — whether local, direct, or remote — implements the same contract:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(sql</span><span style="color:#89DDFF;">,</span><span style="color:#BABED8;"> options)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(sql</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> ...</span><span style="color:#BABED8;">options </span><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">stream</span><span style="color:#BABED8;">(sql</span><span style="color:#89DDFF;">,</span><span style="color:#BABED8;"> options)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">transaction</span><span style="color:#BABED8;">(fn)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(selector</span><span style="color:#89DDFF;">,</span><span style="color:#BABED8;"> handler)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This means you keep the same mental model and API contract across client-side and server-side codebases, for example.</p><p>See the <a href="/api">Core API</a> section for details.</p><hr><h2 id="choose-your-guide" tabindex="-1">Choose Your Guide <a class="header-anchor" href="#choose-your-guide" aria-label="Permalink to &quot;Choose Your Guide&quot;">​</a></h2><p>The following is a map of the LinkedQL guide that fits a specific scenario or application shape.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Shape</th><th style="text-align:left;">Scenario</th><th style="text-align:left;">Start here</th></tr></thead><tbody><tr><td style="text-align:left;">Direct database querying</td><td style="text-align:left;">your app can connect to the database directly</td><td style="text-align:left;"><a href="/guides/postgresql">PostgreSQL</a>, <a href="/guides/mysql">MySQL</a>, <a href="/guides/mariadb">MariaDB</a></td></tr><tr><td style="text-align:left;">Cross-runtime querying</td><td style="text-align:left;">your app runs in the browser, edge, or another boundary and needs remote DB access</td><td style="text-align:left;"><a href="/guides/edge">Edge</a></td></tr><tr><td style="text-align:left;">Local-first querying</td><td style="text-align:left;">you want the database inside the app, with optional upstream sync</td><td style="text-align:left;"><a href="/guides/flashql">FlashQL</a></td></tr><tr><td style="text-align:left;">Hybrid architectures</td><td style="text-align:left;">your app spans multiple runtimes (client, edge, server) and needs to compose queries across them</td><td style="text-align:left;"><a href="/guides/integration-patterns">Integration Patterns</a></td></tr></tbody></table><hr><h2 id="enabling-realtime" tabindex="-1">Enabling Realtime <a class="header-anchor" href="#enabling-realtime" aria-label="Permalink to &quot;Enabling Realtime&quot;">​</a></h2><p>Across database engines or client APIs, LinkedQL&#39;s realtime capabilities are always exposed the same way:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;">// Live queries</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT * FROM users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;">// Chnagefeeds subscriptions</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">(</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#BABED8;">  console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">commit</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>However, the underlying database must support change tracking.</p><p>On a PostgreSQL database, for example, this requires logical replication to be enabled. Similar requirements apply to MySQL and MariaDB, which rely on Binary Logging (Binlog).</p><p>See the relevant section of the docs for details.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Database / Model</th><th style="text-align:left;">Enabling Realtime</th><th style="text-align:left;">Docs</th></tr></thead><tbody><tr><td style="text-align:left;">PostgreSQL</td><td style="text-align:left;">requires logical replication enabled</td><td style="text-align:left;"><a href="/guides/postgresql#realtime-setup">PostgreSQL realtime setup</a></td></tr><tr><td style="text-align:left;">MySQL</td><td style="text-align:left;">requires Binary Logging (Binlog) enabled</td><td style="text-align:left;"><a href="/guides/mysql#realtime-setup">MySQL realtime setup</a></td></tr><tr><td style="text-align:left;">MariaDB</td><td style="text-align:left;">requires Binary Logging (Binlog) enabled</td><td style="text-align:left;"><a href="/guides/mariadb#realtime-setup">MariaDB realtime setup</a></td></tr><tr><td style="text-align:left;">FlashQL</td><td style="text-align:left;">supports realtime out of the box</td><td style="text-align:left;"><a href="/guides/flashql#realtime-notes">FlashQL realtime notes</a></td></tr><tr><td style="text-align:left;">Edge Connection</td><td style="text-align:left;">inherits the support mode of the upstream database</td><td style="text-align:left;"><a href="/guides/edge#realtime-notes">Edge realtime notes</a></td></tr></tbody></table><hr><h2 id="runtime-tuning-and-operational-flags" tabindex="-1">Runtime Tuning and Operational Flags <a class="header-anchor" href="#runtime-tuning-and-operational-flags" aria-label="Permalink to &quot;Runtime Tuning and Operational Flags&quot;">​</a></h2><p>In addition to dialect-specific configuration, LinkedQL clients also support operational configurations that tune how the client behaves at runtime.</p><p>Use these to balance performance and operational requirements.</p><h3 id="nonddlmode" tabindex="-1"><code>nonDDLMode</code> <a class="header-anchor" href="#nonddlmode" aria-label="Permalink to &quot;\`nonDDLMode\`&quot;">​</a></h3><p><code>nonDDLMode</code> assumes your schema will not change while the process is running.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> PGClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  host</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">localhost</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  database</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">myapp</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  nonDDLMode</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>When enabled, LinkedQL can safely keep schema inference work cached in memory for the lifetime of the process.</p><p>In practice, this means:</p><ul><li>lower repeated schema-inference overhead</li><li>better fit for production applications with stable deployed schema</li><li>but stale schema snapshots in local/dev environments where schema changes are frequent</li></ul><p>Use it when:</p><ul><li>migrations run outside the app process</li><li>the app treats schema as fixed during normal runtime</li></ul><p>Leave it off when:</p><ul><li>migrations can run while the process is alive</li><li>the app issues DDL dynamically</li><li>you are in exploratory/dev flows where schema churn is normal</li></ul><hr><h2 id="security-and-access-control" tabindex="-1">Security and Access Control <a class="header-anchor" href="#security-and-access-control" aria-label="Permalink to &quot;Security and Access Control&quot;">​</a></h2><p>LinkedQL does not bypass or reimplement database security for the given database — it composes directly with it. This includes PostgreSQL&#39;s Row Level Security (RLS) model.</p><p>Security and Access Control concepts are documented alongside relevant LinkedQL features or capabilities. The table below is your map to those sections of the docs:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Concern</th><th style="text-align:left;">Where to look</th></tr></thead><tbody><tr><td style="text-align:left;">Establishing a security boundary for live queries</td><td style="text-align:left;"><a href="/realtime/live-queries#visibility-and-security">Live Queries: Visibility and Security</a></td></tr><tr><td style="text-align:left;">Establishing a security boundary for changefeed subscriptions</td><td style="text-align:left;"><a href="/realtime/changefeeds#visibility-and-security">Changefeeds: Visibility and Security</a></td></tr><tr><td style="text-align:left;">Implementing authentication or role-based connections over <code>EdgeClient</code></td><td style="text-align:left;"><a href="/guides/edge">Edge Guide</a></td></tr></tbody></table><hr><h2 id="additional-reading" tabindex="-1">Additional Reading <a class="header-anchor" href="#additional-reading" aria-label="Permalink to &quot;Additional Reading&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">If you want to learn about...</th><th style="text-align:left;">Go to...</th></tr></thead><tbody><tr><td style="text-align:left;">the LinkedQL language surface</td><td style="text-align:left;"><a href="/lang">Language Surface</a></td></tr><tr><td style="text-align:left;">LinkedQL&#39;s realtime capabilities</td><td style="text-align:left;"><a href="/realtime">Realtime Capabilities</a></td></tr><tr><td style="text-align:left;">the API contract</td><td style="text-align:left;"><a href="/api">Core API</a></td></tr></tbody></table>`,50)])])}const g=t(n,[["render",o]]);export{h as __pageData,g as default};
